static compose(
  a: AttributeMap | undefined,
  b: AttributeMap | undefined,
  keepNull: boolean,
): AttributeMap | undefined {
  if (typeof a !== 'object') {
    a = {};
  }
  if (typeof b !== 'object') {
    b = {};
  }
  let attributes = Object.keys(b).reduce<AttributeMap>((copy, key) => {
    if (b[key] !== undefined) {
      copy[key] = b[key];
    }
    return copy;
  }, {});
  if (keepNull) {
    attributes = Object.keys(a).reduce<AttributeMap>((copy, key) => {
      if (typeof copy[key] === 'undefined') {
        copy[key] = a[key];
      }
      return copy;
    }, attributes);
  }
  return Object.keys(attributes).length > 0 ? attributes : undefined;
}
```

